## Task Description

Implement build history tracking in the daemon. Each compilation request should be recorded with its outcome, allowing the status command to show recent build activity.

## Design

### Build Record Structure
```rust
// In rchd/src/history.rs (new file)

use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use std::collections::VecDeque;
use std::sync::RwLock;

/// Record of a single build execution
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BuildRecord {
    /// Unique build ID
    pub id: String,
    /// When the build was submitted
    pub submitted_at: DateTime<Utc>,
    /// When the build completed (None if still running)
    pub completed_at: Option<DateTime<Utc>>,
    /// Project identifier
    pub project_id: String,
    /// Worker that handled the build (None if local fallback)
    pub worker_id: Option<String>,
    /// The compilation command
    pub command: String,
    /// Build outcome
    pub outcome: BuildOutcome,
    /// Duration in milliseconds (once completed)
    pub duration_ms: Option<u64>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum BuildOutcome {
    /// Build is still in progress
    InProgress,
    /// Build completed successfully
    Success,
    /// Build failed with exit code
    Failed { exit_code: i32 },
    /// Build was cancelled
    Cancelled,
    /// Fell back to local execution
    LocalFallback { reason: String },
}

impl BuildRecord {
    pub fn new(project_id: String, worker_id: Option<String>, command: String) -> Self {
        Self {
            id: uuid::Uuid::new_v4().to_string(),
            submitted_at: Utc::now(),
            completed_at: None,
            project_id,
            worker_id,
            command,
            outcome: BuildOutcome::InProgress,
            duration_ms: None,
        }
    }

    pub fn complete(&mut self, outcome: BuildOutcome) {
        self.completed_at = Some(Utc::now());
        self.duration_ms = Some(
            (self.completed_at.unwrap() - self.submitted_at)
                .num_milliseconds() as u64
        );
        self.outcome = outcome;
    }

    pub fn is_complete(&self) -> bool {
        self.completed_at.is_some()
    }
}
```

### History Manager
```rust
/// Manages build history with bounded memory usage
pub struct BuildHistory {
    /// Recent builds (newest first)
    records: RwLock<VecDeque<BuildRecord>>,
    /// Maximum number of records to retain
    max_records: usize,
}

impl BuildHistory {
    pub fn new(max_records: usize) -> Self {
        Self {
            records: RwLock::new(VecDeque::with_capacity(max_records)),
            max_records,
        }
    }

    /// Record a new build starting
    pub fn record_start(
        &self,
        project_id: String,
        worker_id: Option<String>,
        command: String,
    ) -> String {
        let record = BuildRecord::new(project_id, worker_id, command);
        let id = record.id.clone();

        let mut records = self.records.write().unwrap();
        records.push_front(record);

        // Trim if over capacity
        while records.len() > self.max_records {
            records.pop_back();
        }

        id
    }

    /// Record build completion
    pub fn record_complete(&self, build_id: &str, outcome: BuildOutcome) {
        let mut records = self.records.write().unwrap();
        if let Some(record) = records.iter_mut().find(|r| r.id == build_id) {
            record.complete(outcome);
        }
    }

    /// Get recent builds
    pub fn recent(&self, count: usize) -> Vec<BuildRecord> {
        let records = self.records.read().unwrap();
        records.iter().take(count).cloned().collect()
    }

    /// Get builds for a specific project
    pub fn for_project(&self, project_id: &str, count: usize) -> Vec<BuildRecord> {
        let records = self.records.read().unwrap();
        records
            .iter()
            .filter(|r| r.project_id == project_id)
            .take(count)
            .cloned()
            .collect()
    }

    /// Get currently running builds
    pub fn in_progress(&self) -> Vec<BuildRecord> {
        let records = self.records.read().unwrap();
        records
            .iter()
            .filter(|r| !r.is_complete())
            .cloned()
            .collect()
    }

    /// Get statistics
    pub fn stats(&self) -> BuildStats {
        let records = self.records.read().unwrap();
        let total = records.len();
        let success = records.iter().filter(|r| matches!(r.outcome, BuildOutcome::Success)).count();
        let failed = records.iter().filter(|r| matches!(r.outcome, BuildOutcome::Failed { .. })).count();
        let local = records.iter().filter(|r| matches!(r.outcome, BuildOutcome::LocalFallback { .. })).count();

        BuildStats { total, success, failed, local_fallback: local }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BuildStats {
    pub total: usize,
    pub success: usize,
    pub failed: usize,
    pub local_fallback: usize,
}
